svg.script:
function showPopup(id) {
  // Hide all popups first
  var all = document.querySelectorAll('[id$="-popup"]');
  all.forEach(function(el) { el.setAttribute('display', 'none'); });
  // Show the target
  var el = document.getElementById(id);
  if (el) el.setAttribute('display', 'inline');
}
function hidePopup(id) {
  var el = document.getElementById(id);
  if (el) el.setAttribute('display', 'none');
}
// Click outside popup to close
document.addEventListener('click', function(e) {
  var target = e.target;
  // If click is on a node (has onclick with showPopup) or close button, ignore
  if (target.closest && target.closest('.node')) return;
  if (target.getAttribute && target.getAttribute('onclick') && target.getAttribute('onclick').startsWith('hide')) return;
  // Close all popups if click is not on a popup rect or its children
  var inPopup = false;
  var allPopups = document.querySelectorAll('[id$="-popup"]');
  allPopups.forEach(function(p) {
    if (p.contains(target)) inPopup = true;
  });
  if (!inPopup) {
    allPopups.forEach(function(p) { p.setAttribute('display', 'none'); });
  }
});
